actually I would completely forget about smart-table for your test. You want to test that your function stGetTableData behaves in such way for such input, that way for that input, etc
The idea of unit tests is to abstract dependant components. 

A pseudo example:

```Javascript
describe('myController', function () {
 var ctrl;
 var http;

 beforeEach(inject(function ($controller, $httpBackend) {
	//here we will assert on http request it could/should be done by mocking companyResource to better isolate the code to test.
	//So in our test we will somehow test CompanyResource service and stUrlParams filter which can be considered as bad for unit tests
	http = $httpBackend;
	//pass mocks in place of the dependencies you want to abstract
	ctrl = $controller('myController', {dependency1: MockDependency1});
 }));

 afterEach(function () {
	//assertion on http request
	http.verifyNoOutstandingRequest();
	http.verifyNoOutstandingExpectation();
 });


 it('should set the new data set for that table state', function () {
	//input
	var tableState = {
	 sort: {predicate: 'prop1'},
	 search: {},
	 pagination: {}
	};
	//expected result
	var dataSet = {
	 companies: [{id: 1}, {id: 2}],
	 pages: 3
	};

	//expect http call (cf afterEach)
	http.expectGET('www.example.com/companies?sort=prop1').respond(200, dataSet);

	//code to test
	ctrl.stGetTableData(tableState);

	//initial state
	expect(ctrl.stCompaniesTable).toEqual(whatever);

	http.flush();

	//after our code to test has run
	expect(ctrl.stCompaniesTable).toEqual(dataSet.companies);
	expect(tableState.pagination.numberOfPages).toEqual(3);

 });

 it('should set the new data set for that other table state ', function () {
	// ... etc 
 });

});
```



Then to test directives, I suggest you look at the examples of this repository

